+      return Cond;
+    // A ? (A || B) : false -> A
+    if (match(FalseVal, m_ZeroInt()) &&
+        match(TrueVal, m_c_LogicalOr(m_Specific(Cond), m_Value())))
+      return Cond;
+
     // (X || Y) ? X : Y --> X (commuted 2 ways)
     if (match(Cond, m_c_LogicalOr(m_Specific(TrueVal), m_Specific(FalseVal))))
       return TrueVal;
